import '../../models/course.dart';import '../../models/import_result.dart';import '../../../core/utils/color_utils.dart';
class IcsParser{int _ci=0;ImportResult parse(String ics){_ci=0;try{final courses=<Course>[];final lines=ics.split('\n');String? name,loc;int? dow,ss,ee;for(final line in lines){if(line.startsWith('SUMMARY:'))name=line.substring(8).trim();if(line.startsWith('LOCATION:'))loc=line.substring(9).trim();if(line.startsWith('DTSTART:')){final d=line.substring(7).trim();if(d.length>=13){final day=int.tryParse(d.substring(6,8))??0;final h=int.tryParse(d.substring(9,11))??0;final m=int.tryParse(d.substring(11,13))??0;dow=DateTime(2025,day<31?1:day,day>0?day:1).weekday;ss=_ts(h,m);}}if(line.startsWith('DTEND:')){final d=line.substring(6).trim();if(d.length>=13){ee=_ts(int.tryParse(d.substring(9,11))??0,int.tryParse(d.substring(11,13))??0)-1;}}if(line.startsWith('END:VEVENT')&&name!=null&&dow!=null){courses.add(Course(courseId:'ics_$_ci',name:name!,teacher:'',location:loc??'',dayOfWeek:dow!,startSection:ss??1,endSection:ee??2,weeks:List.generate(16,(i)=>i+1),colorHex:_nc()));name=null;loc=null;dow=null;ss=null;ee=null;}}if(courses.isEmpty)return ImportResult.failure('empty ics');return ImportResult.success(courses);}catch(e){return ImportResult.failure('ics err: $e');}}int _ts(int h,int m){final t=h*60+m;const s=[0,480,535,600,655,840,895,960,1015,1140,1195,1250,1305];for(var i=0;i<s.length;i++){if(t<s[i])return i.clamp(1,12);}return 12;}String _nc(){final c=ColorUtils.getByIndex(_ci);_ci++;return'#${c.toARGB32().toRadixString(16).padLeft(8,'0').substring(2)}';}}
